"use client"; // Required for useState/useEffect

import { useState, useEffect } from "react";
import axios from "axios";

const API = process.env.NEXT_PUBLIC_API_URL;

export default function Home() {
  const [campaigns, setCampaigns] = useState([]);
  const [form, setForm] = useState({
    name: "",
    platform: "Meta",
    budget: "",
    status: "Active",
  });
  const [editId, setEditId] = useState<number | null>(null);

  const fetchCampaigns = async () => {
    const res = await axios.get(`${API}/campaigns/`);
    setCampaigns(res.data);
  };

  useEffect(() => {
    fetchCampaigns();
  }, []);

  const handleSubmit = async () => {
    if (editId) {
      await axios.put(`${API}/campaigns/${editId}/`, form);
      setEditId(null);
    } else {
      await axios.post(`${API}/campaigns/`, form);
    }
    setForm({ name: "", platform: "Meta", budget: "", status: "Active" });
    fetchCampaigns();
  };

  const handleEdit = (c: any) => {
    setForm({
      name: c.name,
      platform: c.platform,
      budget: c.budget,
      status: c.status,
    });
    setEditId(c.id);
  };

  const handleDelete = async (id: number) => {
    await axios.delete(`${API}/campaigns/${id}/`);
    fetchCampaigns();
  };

  return (
    <div style={{ padding: 30 }}>
      <h1>Campaign Tracker</h1>

      <h2>{editId ? "Edit Campaign" : "Add Campaign"}</h2>
      <input
        placeholder="Name"
        value={form.name}
        onChange={(e) => setForm({ ...form, name: e.target.value })}
      />
      <input
        placeholder="Budget"
        type="number"
        value={form.budget}
        onChange={(e) => setForm({ ...form, budget: e.target.value })}
      />
      <select
        value={form.platform}
        onChange={(e) => setForm({ ...form, platform: e.target.value })}
      >
        <option>Meta</option>
        <option>Google</option>
        <option>Instagram</option>
      </select>
      <select
        value={form.status}
        onChange={(e) => setForm({ ...form, status: e.target.value })}
      >
        <option>Active</option>
        <option>Paused</option>
        <option>Completed</option>
      </select>
      <button onClick={handleSubmit}>{editId ? "Update" : "Create"}</button>

      <h2>Campaign List</h2>
      {campaigns.map((c: any) => (
        <div
          key={c.id}
          style={{
            border: "1px solid gray",
            margin: "10px 0",
            padding: 10,
            borderRadius: 5,
          }}
        >
          <strong>{c.name}</strong> | {c.platform} | ${c.budget} | {c.status}
          <br />
          <button onClick={() => handleEdit(c)}>Edit</button>
          <button onClick={() => handleDelete(c.id)}>Delete</button>
        </div>
      ))}
    </div>
  );
}
